UPDATE sys_user
SET deleted = #{deleted},
    updated_at = NOW(),
    updated_by = #{updatedBy}
WHERE id = #{id}

UPDATE sys_user
SET login_fail_count = #{loginFailCount},
    lock_time = #{lockTime},
    updated_at = NOW(),
    updated_by = #{updatedBy}
WHERE id = #{id}

UPDATE sys_user
SET login_fail_count = 0,
    lock_time = NULL,
    updated_at = NOW(),
    updated_by = #{updatedBy}
WHERE id = #{id}
